import './App.css';

import ListofPlayers from './Components/ListofPlayers';
import Scorebelow70 from './Components/Scorebelow70';
import OddPlayers from './Components/OddPlayers';
import EvenPlayers from './Components/EvenPlayers';
import ListofIndianPlayers from './Components/ListofIndianPlayers';

function App() {

  const flag = true;

  const players = [

    { name: "Mr. Jack", score: 50 },
    { name: "Mr. Michael", score: 70 },
    { name: "Mr. John", score: 40 },
    { name: "Mr. Ann", score: 61 },
    { name: "Mr. Elisabeth", score: 61 },
    { name: "Mr. Sachin", score: 95 },
    { name: "Mr. Dhoni", score: 100 },
    { name: "Mr. Virat", score: 84 },
    { name: "Mr. Jadeja", score: 64 },
    { name: "Mr. Raina", score: 75 },
    { name: "Mr. Rohit", score: 80 }

  ];

  const IndianTeam = [

    "Sachin",
    "Dhoni",
    "Virat",
    "Rohit",
    "Yuvraj",
    "Raina"

  ];

  const T20players = [

    "First Player",
    "Second Player",
    "Third Player"

  ];

  const RanjiPlayers = [

    "Fourth Player",
    "Fifth Player",
    "Sixth Player"

  ];

  const IndianPlayers = [...T20players, ...RanjiPlayers];

  if (flag === true) {

    return (

      <div>

        <h1>List of Players</h1>

        <ListofPlayers players={players} />

        <hr />

        <h1>List of Players having Scores Less than 70</h1>

        <Scorebelow70 players={players} />

      </div>

    );

  }

  else {

    return (

      <div>

        <h1>Indian Team</h1>

        <h1>Odd Players</h1>

        <OddPlayers IndianTeam={IndianTeam} />

        <hr />

        <h1>Even Players</h1>

        <EvenPlayers IndianTeam={IndianTeam} />

        <hr />

        <h1>List of Indian Players Merged:</h1>

        <ListofIndianPlayers IndianPlayers={IndianPlayers} />

      </div>

    );

  }

}

export default App;
